 1→import { useEffect } from 'react';
 2→import { SketchProvider, useSketch } from './app/SketchProvider';
 3→import { SketchEditorProvider } from './app/SketchEditorProvider';
 4→import SketchToolbar from './ui/SketchToolbar';
 5→import SketchSidebar from './ui/SketchSidebar';
 6→import SketchCanvas from './renderers/SketchCanvas';
 7→import SketchPropertiesPanel from './ui/SketchPropertiesPanel';
 8→import SketchPreviewPanel from './renderers/SketchPreviewPanel';
 9→import { saveSketchProject } from './persistence/sketchStorage';
10→import styles from './SketchWorkspace.module.css';
11→
12→function SketchInner() {
13→  const { project, isDirty, dispatch } = useSketch();
14→
15→  // Autosave
16→  useEffect(() => {
17→    if (!isDirty) return;
18→    const timer = setTimeout(() => {
19→      saveSketchProject(project);
20→      dispatch({ type: 'MARK_SAVED' });
21→    }, 5000);
22→    return () => clearTimeout(timer);
23→  }, [isDirty, project, dispatch]);
24→
25→  return (
26→    <SketchEditorProvider>
27→      <div className={styles.layout}>
28→        <div className={styles.toolbar}>
29→          <SketchToolbar />
30→        </div>
31→        <div className={styles.sidebar}>
32→          <SketchSidebar />
33→        </div>
34→        <div className={styles.canvas}>
35→          <SketchCanvas />
36→        </div>
37→        <div className={styles.rightPanel}>
38→          <SketchPropertiesPanel />
39→          <SketchPreviewPanel />
40→        </div>
41→      </div>
42→    </SketchEditorProvider>
43→  );
44→}
45→
46→export default function SketchWorkspace({ initialProject }) {
47→  return (
48→    <div className="editorRoot">
49→      <SketchProvider initialProject={initialProject}>
50→        <SketchInner />
51→      </SketchProvider>
52→    </div>
53→  );
54→}
