330→export default function SketchPropertiesPanel() {
331→  const { getPart, dispatch, project } = useSketch();
332→  const { selectedId } = useSketchEditor();
333→
334→  const part = selectedId ? getPart(selectedId) : null;
335→
336→  if (!part) {
337→    return (
338→      <div className={styles.panel}>
339→        <div className={styles.header}>Properties</div>
340→        <div className={styles.empty}>Select a part to view its properties</div>
341→      </div>
342→    );
343→  }
344→
345→  const handleUpdate = (changes) => {
346→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...changes } });
347→  };
348→
349→  const handlePositionUpdate = (posChanges) => {
350→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, position: { ...part.position, ...posChanges } } });
351→  };
352→
353→  const handleDuplicate = () => {
354→    dispatch({ type: 'PART_CLONE', partId: part.id });
355→  };
356→
357→  const isDimension = part.type === 'dimension';
358→  const FieldsComponent = isDimension ? null : partFieldComponents[part.type];
359→
360→  // Find assembly this part belongs to
361→  const assembly = part.assemblyId
362→    ? project.assemblies.find((a) => a.id === part.assemblyId)
363→    : null;
364→
365→  return (
366→    <div className={styles.panel}>
367→      <div className={styles.header}>Properties</div>
368→
369→      <div className={styles.content}>
370→        {/* Name */}
371→        <TextInput label="Name" value={part.name} onChange={(v) => handleUpdate({ name: v })} />
372→
373→        {/* Type badge */}
374→        <div className={styles.field}>
375→          <span className={styles.fieldLabel}>Type</span>
376→          <span className={styles.typeBadge}>{part.type}</span>
377→        </div>
378→
379→        {/* Position (skip for dimensions) */}
380→        {!isDimension && (
381→          <PositionSection position={part.position} onUpdate={handlePositionUpdate} />
382→        )}
383→
384→        {/* Dimension-specific fields */}
385→        {isDimension && (
386→          <div className={styles.fieldGroup}>
387→            <span className={styles.groupTitle}>Dimension</span>
388→            <DimensionFields part={part} onUpdate={handleUpdate} dispatch={dispatch} project={project} />
389→          </div>
390→        )}
391→
392→        {/* Type-specific dimensions */}
393→        {FieldsComponent && (
394→          <div className={styles.fieldGroup}>
395→            <span className={styles.groupTitle}>Dimensions</span>
396→            <FieldsComponent part={part} onUpdate={handleUpdate} />
397→          </div>
398→        )}
399→
400→        {/* Style (skip for dimensions) */}
401→        {!isDimension && (
402→          <div className={styles.fieldGroup}>
403→            <span className={styles.groupTitle}>Style</span>
404→            <label className={styles.field}>
405→              <span className={styles.fieldLabel}>Fill</span>
406→              <input
407→                type="color"
408→                value={part.fill === 'none' ? '#ffffff' : part.fill}
409→                onChange={(e) => handleUpdate({ fill: e.target.value })}
410→                className={styles.colorInput}
411→              />
412→            </label>
413→            <label className={styles.field}>
414→              <span className={styles.fieldLabel}>Stroke</span>
415→              <input
416→                type="color"
417→                value={part.stroke || '#1E2433'}
418→                onChange={(e) => handleUpdate({ stroke: e.target.value })}
419→                className={styles.colorInput}
420→              />
421→            </label>
422→          </div>
423→        )}
424→
425→        {/* Assembly (skip for dimensions) */}
426→        {!isDimension && (
427→          <div className={styles.fieldGroup}>
428→            <span className={styles.groupTitle}>Assembly</span>
429→            <div className={styles.field}>
430→              <span className={styles.fieldLabel}>{assembly ? assembly.name : 'None'}</span>
431→            </div>
432→          </div>
433→        )}
434→
435→        {/* Constraints (skip for dimensions) */}
436→        {!isDimension && (
437→          <ConstraintsSection part={part} project={project} dispatch={dispatch} />
438→        )}
439→
440→        {/* Duplicate button */}
441→        {!isDimension && (
442→          <button className={styles.duplicateBtn} onClick={handleDuplicate}>
443→            Duplicate
444→          </button>
445→        )}
446→      </div>
447→    </div>
448→  );
449→}
